import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { GuestDataService } from '../../../core/services/guest-data.service';

@Component({
  selector: 'app-login-prompt',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div class="login-prompt" *ngIf="!authService.isLoggedIn() && guestDataService.hasGuestData()">
      <div class="prompt-content">
        <div class="icon">💾</div>
        <div class="message">
          <h4>Save Your Progress!</h4>
          <p>You have {{ guestAnalysisCount }} resume analysis. Sign up or log in to save your data permanently and access it from any device.</p>
        </div>
        <div class="actions">
          <button class="btn-primary" (click)="goToRegister()">Sign Up</button>
          <button class="btn-secondary" (click)="goToLogin()">Log In</button>
          <button class="btn-dismiss" (click)="dismiss()">×</button>
        </div>
      </div>
    </div>
  `,
  styles: [`
    .login-prompt {
      position: fixed;
      bottom: 20px;
      right: 20px;
      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
      color: white;
      border-radius: 12px;
      box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
      max-width: 350px;
      z-index: 1000;
      animation: slideIn 0.3s ease-out;
    }

    @keyframes slideIn {
      from {
        transform: translateX(100%);
        opacity: 0;
      }
      to {
        transform: translateX(0);
        opacity: 1;
      }
    }

    .prompt-content {
      padding: 20px;
      display: flex;
      align-items: flex-start;
      gap: 15px;
      position: relative;
    }

    .icon {
      font-size: 24px;
      flex-shrink: 0;
    }

    .message h4 {
      margin: 0 0 8px 0;
      font-size: 16px;
      font-weight: 600;
    }

    .message p {
      margin: 0 0 15px 0;
      font-size: 14px;
      opacity: 0.9;
      line-height: 1.4;
    }

    .actions {
      display: flex;
      gap: 8px;
      flex-wrap: wrap;
    }

    .btn-primary, .btn-secondary {
      padding: 8px 16px;
      border: none;
      border-radius: 6px;
      font-size: 14px;
      font-weight: 500;
      cursor: pointer;
      transition: all 0.2s;
    }

    .btn-primary {
      background: rgba(255, 255, 255, 0.2);
      color: white;
      backdrop-filter: blur(10px);
    }

    .btn-primary:hover {
      background: rgba(255, 255, 255, 0.3);
      transform: translateY(-1px);
    }

    .btn-secondary {
      background: transparent;
      color: white;
      border: 1px solid rgba(255, 255, 255, 0.3);
    }

    .btn-secondary:hover {
      background: rgba(255, 255, 255, 0.1);
      transform: translateY(-1px);
    }

    .btn-dismiss {
      position: absolute;
      top: 10px;
      right: 10px;
      background: none;
      border: none;
      color: white;
      font-size: 18px;
      cursor: pointer;
      opacity: 0.7;
      width: 24px;
      height: 24px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      transition: all 0.2s;
    }

    .btn-dismiss:hover {
      opacity: 1;
      background: rgba(255, 255, 255, 0.1);
    }

    @media (max-width: 480px) {
      .login-prompt {
        bottom: 10px;
        right: 10px;
        left: 10px;
        max-width: none;
      }
    }
  `]
})
export class LoginPromptComponent {
  authService = inject(AuthService);
  guestDataService = inject(GuestDataService);
  private router = inject(Router);
  private dismissed = false;

  get guestAnalysisCount(): number {
    return this.guestDataService.getGuestAnalyses().length;
  }

  goToRegister(): void {
    this.router.navigate(['/register']);
  }

  goToLogin(): void {
    this.router.navigate(['/login']);
  }

  dismiss(): void {
    this.dismissed = true;
    // Store dismissal in sessionStorage so it doesn't show again this session
    sessionStorage.setItem('login-prompt-dismissed', 'true');
  }

  ngOnInit(): void {
    // Check if already dismissed this session
    this.dismissed = sessionStorage.getItem('login-prompt-dismissed') === 'true';
  }
}
